import React, {forwardRef, type PropsWithChildren} from "react";
import {ResponsiveElement, useSeparator} from "../../../../Factory";
import type {IGridComponent, IStyleClasses} from "@lmb-it/kitsconcerto-types";
import { toNativeValue } from "@lmb-it/kitsconcertomobile";

type IsolatedGrid = Omit<IGridComponent, keyof IStyleClasses>

const pickFirstResponsive = <T,>(v: any): T | undefined => {
    if (v == null) return undefined;
    if (Array.isArray(v)) return v[0] as T;
    if (typeof v === "object") {
        const order = ["base", "xs", "sm", "md", "lg", "xl", "xxl", "xxxl"];
        for (const k of order) if (k in v) return v[k] as T;
        const first = Object.values(v)[0];
        return first as T;
    }
    return v as T;
};

// convert numeric or string column counts into tailwind grid-cols-*
const extractGridCols = (tpl?: unknown): string | undefined => {
    if (typeof tpl === "number") return `grid-cols-${tpl}`;
    if (typeof tpl === "string") {
        const match = tpl.match(/repeat\((\d+)\s*,/i);
        if (match) return `grid-cols-${match[1]}`;
        if (tpl.includes("grid-cols-")) return tpl;
    }
    return undefined;
};

const Grid = forwardRef<any, PropsWithChildren<IGridComponent>>((props, ref) => {
    const { cssProps, nativeProps } = useSeparator<IGridComponent>(props);
    const { children, className, _extra, ...rest } = nativeProps;

    // derive grid-cols count
    const columns =
        rest.columns ??
        pickFirstResponsive<number | string>(cssProps.columns) ??
        pickFirstResponsive<string>(cssProps.gridTemplateColumns);

    const gridColsClass = extractGridCols(columns) ?? '';

    // Extract layout props that the Gluestack Grid needs as direct props
    // (it uses cssInterop to extract these from className → props for layout calculations)
    const gapValue = pickFirstResponsive(cssProps.gap);
    const columnGapValue = pickFirstResponsive(cssProps.columnGap);
    const rowGapValue = pickFirstResponsive(cssProps.rowGap);
    const paddingValue = pickFirstResponsive(cssProps.p ?? cssProps.padding);

    // Remove layout props from cssProps so they don't conflict as inline styles
    const { gap: _g, columnGap: _cg, rowGap: _rg, p: _p, padding: _pad, columns: _c, gridTemplateColumns: _gt, ...restCssProps } = cssProps as any;

    // Pre-process children: inject _extra with col-span class so the Gluestack Grid
    // can read it before children render (it reads child.props._extra.className)
    const processedChildren = React.Children.map(children, (child: any) => {
        if (!React.isValidElement(child)) return child;
        const childProps = child.props as any;
        const colSpan = childProps?.colSpan;
        let colSpanClass = '';
        if (typeof colSpan === "number") colSpanClass = `col-span-${colSpan}`;
        else if (typeof colSpan === "string") colSpanClass = colSpan.includes("col-span-") ? colSpan : `col-span-${colSpan}`;
        if (!colSpanClass) return child;
        return React.cloneElement(child, {
            _extra: {
                ...(typeof childProps._extra === "object" ? childProps._extra : {}),
                className: colSpanClass,
            },
        } as any);
    });

    console.log({
        ...rest,
        gap: gapValue != null ? toNativeValue(gapValue) : undefined,
        columnGap: columnGapValue != null ? toNativeValue(columnGapValue) : undefined,
        rowGap: rowGapValue != null ? toNativeValue(rowGapValue) : undefined,
        padding: paddingValue != null ? toNativeValue(paddingValue) : undefined,
        _extra: { ...(typeof _extra === "object" ? _extra : {}), className: gridColsClass },
    })

    return (
        <ResponsiveElement<IsolatedGrid>
            ref={ref}
            as="Grid"
            cssProps={{
                width:'100%',
                ...restCssProps
            }}
            nativeProps={{
                ...rest,
                // @ts-ignore
                gap: gapValue != null ? toNativeValue(gapValue) : undefined,
                columnGap: columnGapValue != null ? toNativeValue(columnGapValue) : undefined,
                rowGap: rowGapValue != null ? toNativeValue(rowGapValue) : undefined,
                padding: paddingValue != null ? toNativeValue(paddingValue) : undefined,
                _extra: { ...(typeof _extra === "object" ? _extra : {}), className: gridColsClass },
            }}
        >
            {processedChildren}
        </ResponsiveElement>
    );
});

export default Grid;
